#include <stddef.h>
#include <string.h>

#include <comp421/hardware.h>
#include <comp421/yalnix.h>

typedef void (*TrapHandler)(ExceptionInfo *);

static TrapHandler vector_table[TRAP_VECTOR_SIZE];
static struct pte region0_pt[PAGE_TABLE_LEN];
static struct pte region1_pt[PAGE_TABLE_LEN];

static unsigned int free_frames[NUM_VPN];
static unsigned int free_frame_count;
static unsigned int total_phys_pages;

static void *kernel_break;
static int vm_enabled;

static inline unsigned int
addr_to_pfn(unsigned long addr)
{
    return (unsigned int)(addr >> PAGESHIFT);
}

static inline unsigned int
region1_index(unsigned long addr)
{
    return (unsigned int)((addr - VMEM_1_BASE) >> PAGESHIFT);
}

static void
reserve_frame(unsigned int pfn)
{
    unsigned int i;

    for (i = 0; i < free_frame_count; i++) {
        if (free_frames[i] == pfn) {
            free_frames[i] = free_frames[free_frame_count - 1];
            free_frame_count--;
            return;
        }
    }
}

static void
push_free_frame(unsigned int pfn)
{
    if (free_frame_count < total_phys_pages) {
        free_frames[free_frame_count++] = pfn;
    }
}

static int
pop_free_frame(unsigned int *pfn)
{
    if (free_frame_count == 0) {
        return -1;
    }

    free_frame_count--;
    *pfn = free_frames[free_frame_count];
    return 0;
}

static void
set_pte(struct pte *pte, unsigned int pfn, int kprot, int uprot)
{
    pte->valid = 1;
    pte->kprot = (unsigned int)kprot;
    pte->uprot = (unsigned int)uprot;
    pte->pfn = pfn;
    pte->unused = 0;
}

static void
panic_trap(ExceptionInfo *info)
{
    TracePrintf(0, "Unhandled trap %d code %d addr %p pc %p\n",
                info->vector, info->code, info->addr, info->pc);
    Halt();
}

static void
kernel_idle(void)
{
    for (;;) {
        Pause();
    }
}

/*
 * KernelStart - Initialize the Yalnix kernel.
 *
 * Called by the hardware boot sequence to initialize the kernel.
 * Must set up virtual memory, create the idle and init processes,
 * set up trap handlers, and begin running user processes.
 */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    unsigned int i;
    unsigned int text_base_pfn;
    unsigned int text_pages;
    unsigned int break_page_pfn;
    unsigned int stack_base_pfn;

    (void)cmd_args;

    kernel_break = orig_brk;
    vm_enabled = 0;
    total_phys_pages = pmem_size >> PAGESHIFT;
    free_frame_count = 0;

    for (i = 0; i < TRAP_VECTOR_SIZE; i++) {
        vector_table[i] = NULL;
    }
    vector_table[TRAP_KERNEL] = panic_trap;
    vector_table[TRAP_CLOCK] = panic_trap;
    vector_table[TRAP_ILLEGAL] = panic_trap;
    vector_table[TRAP_MEMORY] = panic_trap;
    vector_table[TRAP_MATH] = panic_trap;
    vector_table[TRAP_TTY_RECEIVE] = panic_trap;
    vector_table[TRAP_TTY_TRANSMIT] = panic_trap;
#ifdef _LAB3
    vector_table[TRAP_DISK] = panic_trap;
#endif

    memset(region0_pt, 0, sizeof(region0_pt));
    memset(region1_pt, 0, sizeof(region1_pt));

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)vector_table);

    if (total_phys_pages > NUM_VPN) {
        total_phys_pages = NUM_VPN;
    }

    for (i = MEM_INVALID_PAGES; i < total_phys_pages; i++) {
        free_frames[free_frame_count++] = i;
    }

    text_base_pfn = addr_to_pfn(VMEM_1_BASE);
    text_pages = (unsigned int)(((unsigned long)&_etext - VMEM_1_BASE) >> PAGESHIFT);
    break_page_pfn = addr_to_pfn(UP_TO_PAGE(kernel_break));
    stack_base_pfn = addr_to_pfn(KERNEL_STACK_BASE);

    for (i = stack_base_pfn; i < addr_to_pfn(KERNEL_STACK_LIMIT); i++) {
        set_pte(&region0_pt[i], i, PROT_READ | PROT_WRITE, PROT_NONE);
        reserve_frame(i);
    }

    for (i = text_base_pfn; i < break_page_pfn; i++) {
        unsigned int idx = i - text_base_pfn;
        int kprot = (i < text_base_pfn + text_pages)
            ? (PROT_READ | PROT_EXEC)
            : (PROT_READ | PROT_WRITE);

        set_pte(&region1_pt[idx], i, kprot, PROT_NONE);
        reserve_frame(i);
    }

    WriteRegister(REG_PTR0, (RCS421RegVal)region0_pt);
    WriteRegister(REG_PTR1, (RCS421RegVal)region1_pt);
    WriteRegister(REG_VM_ENABLE, 1);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_ALL);
    vm_enabled = 1;

    /*
     * The full lab requires constructing idle/init processes and returning
     * into the selected process. This starter only includes the bootstrap
     * file, so we leave the machine in a defined kernel-mode idle loop.
     */
    info->pc = (void *)kernel_idle;
    info->sp = (void *)KERNEL_STACK_LIMIT;
    info->psr |= PSR_MODE;

    TracePrintf(0, "KernelStart: VM enabled, kernel break at %p\n", kernel_break);
}

/*
 * SetKernelBrk - Adjust the kernel heap break.
 *
 * Called by malloc/free in the kernel to grow/shrink the heap.
 * Before virtual memory is enabled, simply track the break.
 * After VM is enabled, must allocate/free physical pages.
 */
int
SetKernelBrk(void *addr)
{
    unsigned long old_break;
    unsigned long new_break;
    unsigned long old_page_end;
    unsigned long new_page_end;
    unsigned long page;

    if (addr == NULL) {
        return 0;
    }

    if (!vm_enabled) {
        if ((unsigned long)addr < (unsigned long)kernel_break) {
            return -1;
        }
        kernel_break = addr;
        return 0;
    }

    if ((unsigned long)addr < VMEM_1_BASE || (unsigned long)addr >= VMEM_1_LIMIT) {
        return -1;
    }

    old_break = (unsigned long)kernel_break;
    new_break = (unsigned long)addr;
    old_page_end = UP_TO_PAGE(old_break);
    new_page_end = UP_TO_PAGE(new_break);

    if (new_page_end > old_page_end) {
        unsigned int allocated[PAGE_TABLE_LEN];
        unsigned int allocated_count = 0;

        for (page = old_page_end; page < new_page_end; page += PAGESIZE) {
            unsigned int pfn;
            unsigned int idx = region1_index(page);

            if (idx >= PAGE_TABLE_LEN || region1_pt[idx].valid) {
                continue;
            }
            if (pop_free_frame(&pfn) < 0) {
                while (allocated_count > 0) {
                    allocated_count--;
                    push_free_frame(allocated[allocated_count]);
                    idx = region1_index(old_page_end + (allocated_count * PAGESIZE));
                    memset(&region1_pt[idx], 0, sizeof(region1_pt[idx]));
                }
                return -1;
            }

            set_pte(&region1_pt[idx], pfn, PROT_READ | PROT_WRITE, PROT_NONE);
            allocated[allocated_count++] = pfn;
        }
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    } else if (new_page_end < old_page_end) {
        for (page = new_page_end; page < old_page_end; page += PAGESIZE) {
            unsigned int idx = region1_index(page);

            if (idx >= PAGE_TABLE_LEN || !region1_pt[idx].valid) {
                continue;
            }

            push_free_frame(region1_pt[idx].pfn);
            memset(&region1_pt[idx], 0, sizeof(region1_pt[idx]));
        }
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_1);
    }

    kernel_break = addr;
    return 0;
}

